import { SolidComponent } from '@/type';
import { cn } from '@/utils/cn';
import { Component, createMemo, For } from 'solid-js';

type BreadcrumbProps = {
  items: SolidComponent[];
  class?: Partial<Record<'root' | 'item', string>>;
  separate?: SolidComponent;
  onItemClick?: (e: MouseEvent) => void;
};
export const Breadcrumb: Component<BreadcrumbProps> = p => {
  const length = createMemo(() => p.items.length - 1);
  return (
    <div class={cn('breadcrumbs', p.separate && 'separate', p.class?.root)}>
      <ul
        onClick={e => {
          if (e.target.tagName !== 'UL' && p.onItemClick) {
            p.onItemClick(e);
          }
        }}
      >
        <For each={p.items}>
          {(item, index) => {
            return (
              <>
                <li class={p.class?.item}>{item as Element}</li>
                {index() < length() && p.separate}
              </>
            );
          }}
        </For>
      </ul>
    </div>
  );
};
